  let succeeded = 0;
  let skipped = 0;

  for (const action of actions) {
    const label = `${action.skill} -> ${action.agent}`;

    let stat: Awaited<ReturnType<typeof lstat>>;
    try {
      stat = await lstat(action.target);
    } catch {
